('creator_approved', 'email', '🎉 Welcome to the {{site_name}} creator family',
'<!DOCTYPE html><html><body style="margin:0;background:#f5f7fa;font-family:-apple-system,Segoe UI,sans-serif;"><table width="100%" cellpadding="0" cellspacing="0" style="padding:32px 16px;"><tr><td align="center"><table width="600" style="background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.06);"><tr><td style="background:linear-gradient(135deg,#e0365b,#7c3aed);padding:36px;text-align:center;color:#fff;"><div style="font-size:54px;">🎉</div><h1 style="margin:12px 0 0;font-size:26px;">You are approved!</h1></td></tr><tr><td style="padding:32px;"><p style="font-size:16px;">Hi {{recipient_name}},</p><p style="line-height:1.6;font-size:15px;">Your creator profile is live on {{site_name}}. Fans can now donate, gift, vote, and buy your merch.</p><a href="{{action_url}}" style="display:inline-block;background:#e0365b;color:#fff;padding:14px 28px;border-radius:12px;text-decoration:none;font-weight:600;margin-top:8px;">Open Creator Dashboard</a><p style="margin-top:24px;color:#6b7280;font-size:14px;">Pro tip: install {{site_name}} to your home screen for instant access to earnings, notifications, and M-PESA payouts.</p></td></tr><tr><td style="background:#f9fafb;padding:20px;text-align:center;font-size:12px;color:#9ca3af;">© {{site_name}}</td></tr></table></td></tr></table></body></html>',
true, '["recipient_name","action_url","site_name"]'::jsonb),

